import { Request, Response, NextFunction } from 'express';
import { GroupService } from './group.service';
import { createGroupValidator, linkTelegramValidator } from './group.validator';
import { CreateGroupDTO, LinkTelegramDTO } from './group.dto';
import { AppError } from '../../utils/app-error';

const groupService = new GroupService();

export class GroupController {
  async createGroup(req: Request, res: Response, next: NextFunction) {
    try {
      const validatedData: CreateGroupDTO = createGroupValidator.parse(req.body);
      const group = await groupService.createGroup(validatedData);
      res.status(201).json({ success: true, data: group });
    } catch (error) {
      next(error);
    }
  }

  async getGroupById(req: Request, res: Response, next: NextFunction) {
    try {
      const groupId = req.params.id;
      const group = await groupService.getGroupById(groupId);
      if (!group) {
        throw new AppError('Group not found', 404, 'GROUP_NOT_FOUND');
      }
      res.json({ success: true, data: group });
    } catch (error) {
      next(error);
    }
  }

  async linkTelegram(req: Request, res: Response, next: NextFunction) {
    try {
      const validatedData: LinkTelegramDTO = linkTelegramValidator.parse(req.body);
      const group = await groupService.linkTelegram(req.params.id, validatedData.telegramChatId);
      res.json({ success: true, data: group });
    } catch (error) {
      next(error);
    }
  }
}

import { GroupRepository } from './group.repository';
import { CreateGroupDTO } from './group.dto';

const groupRepository = new GroupRepository();

export class GroupService {
  async createGroup(data: CreateGroupDTO) {
    return groupRepository.create(data);
  }

  async getGroupById(id: string) {
    return groupRepository.findById(id);
  }

  async linkTelegram(groupId: string, telegramChatId: string) {
    return groupRepository.update(groupId, { telegramChatId });
  }
}

import { Group } from './group.model';

export class GroupRepository {
  async create(data: any) {
    const group = new Group(data);
    return group.save();
  }

  async findById(id: string) {
    return Group.findById(id);
  }

  async update(id: string, updateData: any) {
    return Group.findByIdAndUpdate(id, updateData, { new: true });
  }
}

import mongoose, { Schema, Document } from 'mongoose';

interface IGroup extends Document {
  name: string;
  description: string;
  adminId: mongoose.Types.ObjectId;
  members: mongoose.Types.ObjectId[];
  telegramChatId?: string;
  createdAt: Date;
}

const groupSchema = new Schema<IGroup>({
  name: { type: String, required: true },
  description: { type: String, required: true },
  adminId: { type: mongoose.Types.ObjectId, required: true },
  members: [{ type: mongoose.Types.ObjectId, required: true }],
  telegramChatId: { type: String },
  createdAt: { type: Date, default: Date.now }
});

export const Group = mongoose.model<IGroup>('Group', groupSchema);

import { z } from 'zod';

export const CreateGroupSchema = z.object({
  name: z.string(),
  description: z.string(),
  adminId: z.string().uuid(),
  members: z.array(z.string().uuid())
});

export const LinkTelegramSchema = z.object({
  telegramChatId: z.string().optional()
});

export type CreateGroupDTO = z.infer<typeof CreateGroupSchema>;
export type LinkTelegramDTO = z.infer<typeof LinkTelegramSchema>;

import { CreateGroupSchema, LinkTelegramSchema } from './group.dto';

export const createGroupValidator = CreateGroupSchema;
export const linkTelegramValidator = LinkTelegramSchema;

export class AppError extends Error {
  public statusCode: number;
  public code: string;

  constructor(message: string, statusCode: number, code: string) {
    super(message);
    this.statusCode = statusCode;
    this.code = code;

    Error.captureStackTrace(this, this.constructor);
  }
}

import { z } from 'zod';

const envSchema = z.object({
  NODE_ENV: z.enum(['development', 'production', 'test']),
  PORT: z.string(),
  MONGODB_URI: z.string(),
  JWT_SECRET: z.string(),
  RATE_LIMIT_MAX: z.string(),
  RATE_LIMIT_WINDOW: z.string()
});

export const validateEnv = (env: NodeJS.ProcessEnv) => {
  return envSchema.parse(env);
};

validateEnv(process.env);
